(()=>{"use strict";const data=window.ATHANAS_LEARNING_CONTENT;if(!data)return;const escapeHtml=(value="")=>String(value).replace(/[&<>'"]/g,(char)=>({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;"}[char]));const externalAttrs=(url)=>/^https?:/i.test(url||"")?' target="_blank" rel="noopener noreferrer"':"";const statusLabel=(status)=>status==="available"||status==="published"?"Available Now":"Coming Soon";function lessonActions(lesson){if(lesson.status!=="published")return'<span class="content-status content-status--soon">Coming Soon</span>';const assignment=data.assignments.find((item)=>item.lessonId===lesson.id);const actions=[`<a class="small-btn content-primary-action" href="${escapeHtml(lesson.videoUrl)}" target="_blank" rel="noopener noreferrer" data-track="lesson_watch" data-track-label="${escapeHtml(lesson.displayTitle)}">Watch Lesson</a>`];if(assignment)actions.push(`<a class="small-btn outline-btn" href="assignments.html#${escapeHtml(assignment.anchor)}" data-track="assignment_open" data-track-label="${escapeHtml(assignment.title)}">Open Assignment</a>`);(lesson.resources||[]).forEach((resource)=>actions.push(`<a class="small-btn outline-btn" href="${escapeHtml(resource.url)}" download data-track="resource_download" data-track-label="${escapeHtml(resource.label)}">${escapeHtml(resource.label)}</a>`));return actions.join("");}
function renderCourses(){const root=document.getElementById("coursesLearningRoot");if(!root)return;root.innerHTML=data.series.map((series,seriesIndex)=>`
      <section class="learning-roadmap-series learning-roadmap-series--${escapeHtml(series.theme)}" id="${escapeHtml(series.anchor)}">
        <div class="learning-roadmap-head">
          <div class="learning-roadmap-icon" aria-hidden="true">${series.icon}</div>
          <div>
            <p class="eyebrow dark">${escapeHtml(series.eyebrow)}</p>
            <h2>${escapeHtml(series.title)}</h2>
            <p>${escapeHtml(series.description)}</p>
          </div>
          <a class="learning-roadmap-youtube" href="youtube.html#${escapeHtml(series.id)}" data-track="youtube_hub_series" data-track-label="${escapeHtml(series.title)}">Open in YouTube Hub <span aria-hidden="true">→</span></a>
        </div>
        <div class="learning-roadmap-list">
          ${series.lessons.map((lesson, lessonIndex) => `<article class="learning-roadmap-item ${lesson.status === "coming-soon" ? "is-coming-soon" : ""}"id="${escapeHtml(lesson.id)}"><div class="learning-roadmap-number"aria-label="Lesson ${lesson.session}">${escapeHtml(lesson.session)}</div><div class="learning-roadmap-copy"><div class="learning-roadmap-meta"><span>${escapeHtml(series.title)}</span><span>${lesson.status==="published"?"Published":"Coming Soon"}</span></div><h3>${escapeHtml(lesson.title)}</h3><p>${escapeHtml(lesson.description)}</p></div><div class="card-actions learning-roadmap-actions">${lessonActions(lesson)}</div></article>`).join("")}
        </div>
      </section>`).join("")+`
      <section class="future-learning-strip" id="future-ict">
        <div><p class="eyebrow dark">Next Skills</p><h2>More practical digital skills are being prepared.</h2></div>
        <div class="future-learning-items">${data.futureSeries.map((item) => `<article><span aria-hidden="true">${item.icon}</span><div><strong>${escapeHtml(item.title)}</strong><p>${escapeHtml(item.description)}</p></div><span class="content-status content-status--soon">Coming Soon</span></article>`).join("")}</div>
      </section>`;}
function renderAssignments(){const root=document.getElementById("assignmentsRoot");if(!root)return;root.innerHTML=data.assignments.map((item)=>`
      <article class="premium-assignment-card" id="${escapeHtml(item.anchor)}">
        <div class="premium-assignment-top">
          <span class="premium-assignment-icon" aria-hidden="true">${item.icon}</span>
          <span class="content-status content-status--available">Available Now</span>
        </div>
        ${item.preview ? `<img class="premium-assignment-preview"loading="lazy"src="${escapeHtml(item.preview)}"alt="Preview for ${escapeHtml(item.title)}">` : ""}
        <p class="premium-assignment-series">${escapeHtml(item.series)}</p>
        <h2>${escapeHtml(item.title)}</h2>
        <p>${escapeHtml(item.description)}</p>
        <ol class="assignment-journey-mini" aria-label="Assignment steps">
          <li><span>1</span>Watch</li><li><span>2</span>Download</li><li><span>3</span>Complete</li><li><span>4</span>Submit</li>
        </ol>
        <div class="card-actions premium-assignment-actions">
          <a class="small-btn" href="${escapeHtml(item.watchUrl)}" target="_blank" rel="noopener noreferrer" data-track="lesson_watch" data-track-label="${escapeHtml(item.title)}">Watch Lesson</a>
          <a class="small-btn outline-btn" href="${escapeHtml(item.downloadUrl)}" download data-track="assignment_download" data-track-label="${escapeHtml(item.title)}">${escapeHtml(item.downloadLabel)}</a>
          <a class="small-btn submit-btn" href="${escapeHtml(item.submitUrl)}" target="_blank" rel="noopener noreferrer" data-track="assignment_submit" data-track-label="${escapeHtml(item.title)}">Submit Assignment</a>
        </div>
      </article>`).join("");}
function renderDownloads(){const root=document.getElementById("downloadsRoot");if(!root)return;const groups=data.downloads.reduce((acc,item)=>{(acc[item.category]||=[]).push(item);return acc;},{});root.innerHTML=Object.entries(groups).map(([category,items])=>`
      <section class="download-category">
        <div class="download-category-head"><div><p class="eyebrow dark">Resource Library</p><h2>${escapeHtml(category)}</h2></div><span>${items.length} ${items.length === 1 ? "file" : "files"}</span></div>
        <div class="download-category-list">
          ${items.map((item) => `<article class="premium-download-row"><span class="premium-download-icon"aria-hidden="true">${item.icon}</span><div class="premium-download-copy"><span class="download-type-badge">${escapeHtml(item.type)}</span><h3>${escapeHtml(item.title)}</h3><p>${escapeHtml(item.description)}</p></div><div class="premium-download-actions"><a class="small-btn"href="${escapeHtml(item.url)}"download data-track="resource_download"data-track-label="${escapeHtml(item.title)}">Download File</a><a class="small-btn outline-btn"href="${escapeHtml(item.relatedUrl)}">Open Assignment</a></div></article>`).join("")}
        </div>
      </section>`).join("")+`
      <section class="download-category download-category--future">
        <div class="download-category-head"><div><p class="eyebrow dark">Growing Library</p><h2>More resources are coming</h2></div></div>
        <p>Future Word, Excel, PowerPoint, Python, education, and school-support resources will be organised here as they become available.</p>
      </section>`;}
function renderTools(){const root=document.getElementById("toolsRoot");if(!root)return;const available=data.tools.filter((item)=>item.status==="available").length;const upcoming=data.tools.filter((item)=>item.status==="coming-soon").length;const availableCount=document.getElementById("toolsAvailableCount");const upcomingCount=document.getElementById("toolsUpcomingCount");if(availableCount)availableCount.textContent=available;if(upcomingCount)upcomingCount.textContent=upcoming;root.innerHTML=data.tools.map((item,index)=>`
      <article class="premium-tool-card premium-tool-card--${escapeHtml(item.id)} ${item.status === "coming-soon" ? "is-coming-soon" : "is-available"}" data-tool-status="${escapeHtml(item.status)}">
        <span class="premium-tool-card-glow" aria-hidden="true"></span>
        <div class="premium-tool-top">
          <span class="premium-tool-index">${String(index + 1).padStart(2, "0")}</span>
          <span class="content-status ${item.status === "available" ? "content-status--available" : "content-status--soon"}">${statusLabel(item.status)}</span>
        </div>
        <div class="premium-tool-visual" aria-hidden="true">
          <span class="premium-tool-orbit"></span>
          <span class="premium-tool-icon">${item.icon}</span>
        </div>
        <div class="premium-tool-tags"><span>${escapeHtml(item.level)}</span><span>${escapeHtml(item.purpose)}</span></div>
        <h2>${escapeHtml(item.title)}</h2>
        <p>${escapeHtml(item.description)}</p>
        ${item.url ? `<a class="small-btn content-primary-action"href="${escapeHtml(item.url)}"data-track="tool_open"data-track-label="${escapeHtml(item.title)}">Open Tool<span aria-hidden="true">→</span></a>` : `<span class="premium-tool-wait"><i aria-hidden="true">✦</i>Being prepared with care</span>`}
      </article>`).join("");const filters=Array.from(document.querySelectorAll("[data-tool-filter]"));const resultCount=document.getElementById("toolsResultCount");const cards=Array.from(root.querySelectorAll("[data-tool-status]"));const applyFilter=(filter)=>{let visible=0;cards.forEach((card)=>{const show=filter==="all"||card.dataset.toolStatus===filter;card.hidden=!show;if(show)visible+=1;});filters.forEach((button)=>{const active=button.dataset.toolFilter===filter;button.classList.toggle("is-active",active);button.setAttribute("aria-pressed",String(active));});if(resultCount){const label=filter==="all"?"all tools":filter==="available"?"available tools":"upcoming tools";resultCount.textContent=`Showing ${visible} ${label}`;}};filters.forEach((button)=>button.addEventListener("click",()=>applyFilter(button.dataset.toolFilter||"all")));applyFilter("all");}
function renderLatest(){const root=document.getElementById("latestLearningRoot");if(!root)return;const featured=data.series.flatMap((series)=>series.lessons).find((lesson)=>lesson.id===data.featuredLessonId);const assignment=data.assignments.find((item)=>item.lessonId===featured?.id);const typing=data.tools.find((item)=>item.id==="typing");const items=[{icon:"💻",title:"Why Technology Is Necessary in Today’s World",url:"why-technology-is-necessary.html",search:"technology article digital growth learning future skills"},{icon:"▶",title:featured.displayTitle,url:"youtube.html#featured",search:`${featured.title} microsoft word visual documents`},{icon:"📝",title:assignment.title,url:`assignments.html#${assignment.anchor}`,search:`${assignment.title} practice assignment`},{icon:"🌱",title:"The Power of Small Beginnings",url:"the-power-of-small-beginnings.html",search:"article inspiration growth small beginnings"},{icon:"⌨",title:typing.title,url:typing.url,search:`${typing.title} typing speed accuracy tool`}];root.innerHTML=items.map((item)=>`<a href="${escapeHtml(item.url)}" class="latest-row search-item" data-search="${escapeHtml(item.search)}"><span class="latest-icon latest-icon--text" aria-hidden="true">${item.icon}</span><span class="latest-title">${escapeHtml(item.title)}</span><span class="latest-arrow" aria-hidden="true">→</span></a>`).join("");}
document.addEventListener("DOMContentLoaded",()=>{renderCourses();renderAssignments();renderDownloads();renderTools();renderLatest();});})();